{
  "domain_analysis": {
    "business_context": "A logistics platform introducing dynamic route optimization that automatically plans and replans driver routes in real-time based on pending deliveries, driver capabilities, and operational events. This spans multiple bounded contexts: route planning, fleet/driver management, delivery lifecycle, and customer notifications.",
    "bounded_context": "Primary: Route Planning. Adjacent: Fleet Management, Delivery Management, Customer Notification",
    "ubiquitous_language": [
      { "term": "Zone", "definition": "A geographic region that scopes both drivers and deliveries. A driver operates within a zone; deliveries belong to a zone. Zone is the primary partitioning unit for route calculation." },
      { "term": "Optimized Route", "definition": "An ordered sequence of delivery stops calculated by the system to minimize travel time/distance for a driver within their zone. It is not a suggestion—it is the system's current plan of record." },
      { "term": "Shift", "definition": "A bounded work period during which a driver is active and eligible for route assignment. Route optimization is triggered at shift start." },
      { "term": "Licensed Vehicle Class", "definition": "A classification of the vehicle a driver is authorized to operate (e.g., motorcycle, van, truck, freight). Determines which deliveries are eligible for assignment to that driver." },
      { "term": "Delivery Stop", "definition": "A single delivery task at a specific location within a route. Has an estimated service time (default 4 minutes, overridable per zone)." },
      { "term": "Stop Service Time", "definition": "The estimated duration a driver spends at each delivery stop. Defaults to 4 minutes globally but is overridable by the operations team at the zone level." },
      { "term": "Next 3 Stops Window", "definition": "A rolling window of the upcoming 3 delivery stops on a driver's active route. Entry into this window triggers customer notification." },
      { "term": "Route Recalculation", "definition": "The act of re-optimizing the remaining stops on a driver's route. Triggered by specific domain events: new delivery added, delivery failure, or driver deviation." },
      { "term": "Driver Deviation", "definition": "When a driver's actual position or stop sequence diverges from the system-planned route. This is detected (not self-reported) and triggers recalculation." },
      { "term": "Failed Delivery", "definition": "A delivery that could not be completed (recipient unavailable, access denied, etc.). Removed from the active route and triggers recalculation of remaining stops." },
      { "term": "Pending Delivery", "definition": "A delivery that has been created and is awaiting assignment to a driver route. Scoped to a zone." },
      { "term": "Vehicle Class Constraint", "definition": "A hard physical constraint linking delivery requirements (size, weight, type) to the vehicle class needed to fulfill them." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A driver MUST NOT be assigned a delivery that requires a vehicle class exceeding their licensed vehicle class.",
      "invariant": true,
      "invariant_justification": "This is a physical and legal constraint. A motorcycle physically cannot carry freight. Violating this results in failed deliveries, regulatory violations, and potential safety hazards. No business policy can override physics or law.",
      "testable_assertion": "For every delivery assigned to a driver, delivery.requiredVehicleClass must be compatible with driver.licensedVehicleClass."
    },
    {
      "id": "BR-2",
      "rule": "Route optimization is triggered automatically when a driver starts their shift, considering all pending deliveries in their zone at that moment.",
      "invariant": false,
      "invariant_justification": "The trigger point (shift start) is a business policy. The company could decide to also trigger on login, or on dispatcher command. The concept of automatic assignment is a workflow choice.",
      "testable_assertion": "When a driver's shift status transitions to 'active', a route optimization request is enqueued containing all pending deliveries in that driver's zone."
    },
    {
      "id": "BR-3",
      "rule": "The route MUST be recalculated when a new delivery is added to a zone that has an active driver route.",
      "invariant": false,
      "invariant_justification": "This is a business policy about responsiveness. The company could choose to batch new deliveries and recalculate every N minutes instead. The system would not be corrupt if recalculation were deferred.",
      "testable_assertion": "When a new delivery is created in a zone with at least one active route, a route recalculation event is emitted for each affected route in that zone."
    },
    {
      "id": "BR-4",
      "rule": "The route MUST be recalculated when a delivery on the active route is marked as failed.",
      "invariant": false,
      "invariant_justification": "Business policy. The failed stop could theoretically remain in the route as a skip marker. Recalculation is the desired behavior, not a system integrity requirement.",
      "testable_assertion": "When a delivery's status transitions to 'failed' and it belongs to an active route, a route recalculation is triggered for that route, and the failed delivery is excluded from the new route."
    },
    {
      "id": "BR-5",
      "rule": "The route MUST be recalculated when a driver manually deviates from the suggested route.",
      "invariant": false,
      "invariant_justification": "Business policy for route accuracy. The system could alternatively flag the deviation without recalculating. This is an operational preference.",
      "testable_assertion": "When the system detects a driver's actual path diverges from the planned route (e.g., skipping a stop, going off-path), a recalculation is triggered using the driver's current position as the new origin."
    },
    {
      "id": "BR-6",
      "rule": "Customers are notified when their delivery enters the 'next 3 stops' window on the driver's active route.",
      "invariant": false,
      "invariant_justification": "The notification trigger (3 stops) is a business-configurable threshold. It could be changed to 2 or 5 stops. The notification itself is a customer experience policy, not a system integrity constraint.",
      "testable_assertion": "When a route's current stop advances such that a delivery moves into position 1, 2, or 3 in the remaining sequence, and no notification has been sent for that delivery in this route cycle, a customer notification is dispatched."
    },
    {
      "id": "BR-7",
      "rule": "The default estimated stop service time is 4 minutes per delivery stop.",
      "invariant": false,
      "invariant_justification": "This is a configurable operational parameter, explicitly stated as overridable.",
      "testable_assertion": "When calculating route ETAs, each stop uses 4 minutes as the service time unless a zone-level override is configured."
    },
    {
      "id": "BR-8",
      "rule": "The operations team can override the stop service time on a per-zone basis.",
      "invariant": false,
      "invariant_justification": "This is an administrative capability, not a system constraint.",
      "testable_assertion": "When a zone has a configured stop service time override, all route calculations for that zone use the override value instead of the 4-minute default."
    },
    {
      "id": "BR-9",
      "rule": "A driver can only be assigned deliveries within their zone.",
      "invariant": true,
      "invariant_justification": "Zone boundaries define operational jurisdiction. A route that crosses zone boundaries would violate the geographic partitioning model, cause SLA conflicts, and corrupt the zone-based optimization model. Cross-zone assignment requires a different workflow (zone transfer).",
      "testable_assertion": "Every delivery on a driver's route must have delivery.zoneId equal to driver.activeZoneId."
    },
    {
      "id": "BR-10",
      "rule": "A route recalculation must preserve the driver's current position as the starting point, not the original shift start location.",
      "invariant": true,
      "invariant_justification": "Recalculating from a stale origin would produce physically impossible routes. The driver is where they are, not where they started. This is a data consistency constraint.",
      "testable_assertion": "When a recalculation is triggered, the optimization algorithm uses the driver's last known GPS position as the route origin."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver starts their shift and there are 5 pending deliveries in their zone, all compatible with their vehicle class",
      "when": "The shift is activated",
      "then": "An optimized route is generated containing all 5 deliveries in an optimized order, with ETAs calculated using the zone's configured stop service time (or 4-min default)"
    },
    {
      "id": "AC-2",
      "given": "A driver has an active route with 8 remaining stops",
      "when": "A new delivery is added to the driver's zone and is compatible with their vehicle class",
      "then": "The route is recalculated from the driver's current position, incorporating the new delivery into the optimized sequence"
    },
    {
      "id": "AC-3",
      "given": "A driver has an active route and delivery #4 in the sequence is marked as failed",
      "when": "The failure is recorded",
      "then": "The route is recalculated excluding the failed delivery, starting from the driver's current position"
    },
    {
      "id": "AC-4",
      "given": "A driver has an active route and deviates from the planned sequence (e.g., skips stop #2 and drives toward stop #4)",
      "when": "The system detects the deviation",
      "then": "The route is recalculated from the driver's current GPS position, re-optimizing all undelivered stops"
    },
    {
      "id": "AC-5",
      "given": "A driver's route has 7 remaining stops and the driver completes stop #1",
      "when": "Stop #1 is completed, making the previous stop #4 now the new stop #3 in the window",
      "then": "The customer for the delivery now at position 3 receives a notification that their delivery is approaching"
    },
    {
      "id": "AC-6",
      "given": "A motorcycle driver is active in a zone with 3 pending deliveries: 2 parcels and 1 freight shipment",
      "when": "The route is calculated",
      "then": "Only the 2 parcel deliveries are included in the route; the freight shipment is excluded from assignment"
    },
    {
      "id": "AC-7",
      "given": "The operations team has set the stop service time for Zone A to 6 minutes",
      "when": "A route is calculated for a driver in Zone A",
      "then": "All ETA calculations use 6 minutes per stop instead of the default 4 minutes"
    },
    {
      "id": "AC-8",
      "given": "A driver is active in Zone A",
      "when": "A new delivery is added to Zone B",
      "then": "The driver's route in Zone A is NOT recalculated, and the Zone B delivery is NOT assigned to the Zone A driver"
    },
    {
      "id": "AC-9",
      "given": "A route recalculation results in a delivery moving into the 'next 3 stops' window that was previously outside it",
      "when": "The recalculated route is committed",
      "then": "The customer for that delivery is notified, even though the notification was triggered by recalculation rather than normal route progression"
    },
    {
      "id": "AC-10",
      "given": "A customer has already been notified that their delivery is in the 'next 3 stops' window",
      "when": "A route recalculation occurs and their delivery remains in the next 3 stops",
      "then": "The customer is NOT notified again (idempotent notification)"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver starts their shift but there are zero pending deliveries in their zone",
      "expected_behavior": "The system creates an empty route (or a 'waiting' state) and begins monitoring the zone for new deliveries. When the first delivery arrives, it triggers route calculation."
    },
    {
      "scenario": "All remaining deliveries on a route are marked as failed",
      "expected_behavior": "The route is completed/closed. The driver is set to an 'idle' or 'awaiting assignment' state within their zone."
    },
    {
      "scenario": "Multiple recalculation triggers fire simultaneously (e.g., new delivery added and another delivery fails at the same time)",
      "expected_behavior": "Recalculations must be serialized or debounced per route. Only one recalculation should execute, incorporating all pending state changes. Concurrent recalculations on the same route would produce conflicting results."
    },
    {
      "scenario": "A driver deviates but then returns to the original route before recalculation completes",
      "expected_behavior": "The recalculation still proceeds using the driver's position at the time of detection. The system should not try to 'cancel' an in-flight recalculation based on the driver returning."
    },
    {
      "scenario": "A delivery is added to a zone with multiple active drivers",
      "expected_behavior": "The system must decide which driver's route to assign the new delivery to. The spec does not define the assignment policy—this needs clarification (nearest driver? least loaded? best route fit?)."
    },
    {
      "scenario": "A recalculation pushes a delivery OUT of the 'next 3 stops' window after the customer was already notified",
      "expected_behavior": "The customer was already told their delivery is close. The system should send an updated notification explaining the delay, or at minimum not send a contradictory 'approaching' notification later when the delivery re-enters the window."
    },
    {
      "scenario": "The driver's GPS signal is lost during a deviation check",
      "expected_behavior": "The system cannot recalculate without a known position. It should use the last known position with a staleness indicator, or defer recalculation until GPS is reacquired."
    },
    {
      "scenario": "A zone's stop service time override is changed while drivers have active routes in that zone",
      "expected_behavior": "Existing ETAs should be recalculated with the new service time, or the change should only apply to newly calculated routes. The spec does not clarify this."
    },
    {
      "scenario": "A delivery requires a vehicle class that no active driver in the zone can fulfill",
      "expected_behavior": "The delivery remains in 'pending' state and is not assigned to any route. Operations should be alerted to the unassignable delivery."
    },
    {
      "scenario": "Driver deviation detection threshold—how far off-route constitutes a 'deviation'?",
      "expected_behavior": "Spec does not define the deviation threshold. This is critical: too sensitive triggers constant recalculation (driver takes a legal alternate street); too loose means stale routes persist. Needs a configurable threshold."
    }
  ],

  "business_impact": {
    "financial": "Route optimization directly reduces fuel costs, increases deliveries per shift, and improves asset utilization. Poor recalculation logic or excessive recalculations could increase compute costs and driver confusion, reducing throughput. Vehicle class enforcement prevents costly failed delivery attempts and potential liability from unsafe assignments.",
    "operational": "Real-time recalculation introduces system complexity—compute load scales with zone density and event frequency. Debouncing/serialization of recalculations is critical to avoid thrashing. Operations team needs tooling for zone-level service time overrides and monitoring of unassignable deliveries.",
    "user": "Customers receive proactive 'approaching' notifications improving satisfaction and reducing missed deliveries. However, false or premature notifications (due to frequent recalculations pushing deliveries in and out of the 3-stop window) will erode trust. Drivers benefit from automated routing but may resist if recalculations are too aggressive or override their local knowledge.",
    "risk": "High risk around recalculation storm scenarios (high-volume zones with frequent new deliveries). Vehicle class violation is a legal/safety risk with zero tolerance. Notification reliability directly impacts customer trust. GPS dependency for deviation detection introduces a single point of failure.",
    "stakeholders_affected": [
      { "group": "Drivers", "impact": "Route automatically planned and replanned. Reduced autonomy but lower cognitive load. Must trust the system's optimization. Deviation detection could feel like surveillance." },
      { "group": "Customers", "impact": "Proactive delivery notifications improve experience. Risk of notification noise or inaccuracy if recalculations are frequent." },
      { "group": "Operations Team", "impact": "New responsibility for zone-level configuration (service time overrides). Need visibility into unassignable deliveries, route quality, and recalculation frequency." },
      { "group": "Dispatchers", "impact": "Reduced manual assignment work, but need override capability for edge cases the algorithm cannot handle." },
      { "group": "Finance/Management", "impact": "Expect measurable improvements in deliveries-per-shift and fuel efficiency. Need KPI dashboards." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec covers the happy path well but leaves several critical operational details ambiguous: multi-driver assignment policy, deviation detection threshold, recalculation concurrency handling, and notification behavior when deliveries move out of the 3-stop window. These are not minor details—they fundamentally affect system behavior under real-world conditions.",
    "high_confidence_areas": [
      "Vehicle class constraint is a hard invariant (physical + legal)",
      "Zone-scoped assignment is a hard invariant",
      "Recalculation trigger events are clearly enumerated",
      "Customer notification trigger (next 3 stops) is well-defined for the happy path",
      "Stop service time default and override mechanism is clear"
    ],
    "low_confidence_areas": [
      "Multi-driver zone assignment policy when a new delivery arrives",
      "Deviation detection: what constitutes a deviation (threshold, method, GPS dependency)",
      "Recalculation concurrency/debouncing strategy",
      "Customer notification behavior when recalculation pushes delivery OUT of the 3-stop window",
      "Whether zone service time changes apply retroactively to active routes",
      "What happens to the freight delivery that no driver in the zone can handle"
    ],
    "assumptions": [
      "A driver operates in exactly one zone per shift (no multi-zone drivers)",
      "Vehicle class compatibility is a simple hierarchy or category match, not a complex multi-attribute comparison",
      "GPS position is available with sufficient accuracy and frequency for deviation detection",
      "Route optimization is a system-internal algorithm; the spec does not prescribe a specific algorithm (TSP variant, etc.)",
      "Notifications are sent at most once per delivery per entry into the 3-stop window (idempotent)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "When a new delivery is added to a zone with multiple active drivers, which driver's route gets the delivery? The spec says 'the system automatically assigns' but does not define the assignment policy for competing drivers in the same zone.",
      "affected_stakeholders": ["Drivers", "Customers", "Operations Team"],
      "options": [
        "Assign to the driver whose route optimization score improves the most with the new delivery",
        "Assign to the nearest driver by current GPS position",
        "Assign to the driver with the fewest remaining stops (load balancing)",
        "Let the dispatcher manually assign, then recalculate that driver's route"
      ],
      "recommendation": "Option A (best route fit) is most consistent with the optimization-first philosophy of the feature, but this needs explicit product team confirmation."
    },
    {
      "type": "ambiguity",
      "description": "What constitutes a 'driver deviation'? The spec says 'manually deviates from the suggested route' but does not define the detection mechanism or threshold. Is it skipping a stop? Going off the GPS path by X meters? Taking an alternate road?",
      "affected_stakeholders": ["Drivers", "Operations Team"],
      "options": [
        "Deviation = driver skips the next planned stop (stop-sequence based)",
        "Deviation = driver is more than X meters from the planned route for more than Y seconds (GPS-path based)",
        "Both: stop-skip detection AND significant GPS path divergence"
      ],
      "recommendation": "Option C (both methods) with configurable thresholds. Stop-skip is deterministic and reliable; GPS-path catches mid-segment detours. But thresholds must be tunable to avoid recalculation storms."
    },
    {
      "type": "ambiguity",
      "description": "What happens to customer notifications when a recalculation pushes a previously-notified delivery BACK outside the 3-stop window? The customer was told 'your delivery is almost here' but now it's 6 stops away.",
      "affected_stakeholders": ["Customers"],
      "options": [
        "Send an updated notification: 'Your delivery time has been updated'",
        "Do nothing—the original notification stands, accept potential customer confusion",
        "Send a delay notification only if the new ETA differs by more than a configurable threshold"
      ],
      "recommendation": "Option C. A small ETA shift (1-2 minutes) doesn't warrant another notification. A significant delay (e.g., >10 minutes) requires proactive communication to maintain trust."
    },
    {
      "type": "missing_context",
      "description": "No concurrency or debouncing strategy is defined for recalculation triggers. In a busy zone, multiple triggers (new delivery, failure, deviation) could fire within seconds, causing a recalculation storm.",
      "affected_stakeholders": ["Operations Team", "Drivers"],
      "options": [
        "Serialize recalculations per route with a short debounce window (e.g., 5-10 seconds)",
        "Queue all triggers and batch-process on a fixed interval",
        "Immediate recalculation with in-flight cancellation of superseded calculations"
      ],
      "recommendation": "Option A (serialize + debounce). Batching (Option B) introduces unacceptable latency. Immediate with cancellation (Option C) is complex and wasteful. A short debounce window captures co-occurring events without noticeable delay."
    }
  ],

  "rejection_reasons": []
}

